INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トワイライトキャラバン", 159, 0, "髙野麻美", 13, 7, 5, "アンナ", 17, "前世を信じる中二病患者、「疾風の冥姫」", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 100901, "魔族", "A", 45, "小説執筆");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("自警団（カォン）", 155, 0, "内田真礼", 10, 9, 22, "マホ", 16, "マホマホ王国のプリンセス", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 101001, "獣人族", "O", 42, "空想、ぬいぐるみ集め");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ラビリンス", 156, 0, "阿澄佳奈", 3, 8, 25, "リノ", 15, "人懐っこくてマシンガントークな妹系少女", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 101101, "ヒューマン", "A", 44, "お裁縫");
